"use strict";document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("informationModal"),d=document.getElementById("triggerModalBtn"),n=document.getElementById("closeModalBtn");d.addEventListener("click",()=>{e.classList.remove("hidden"),console.log("Modal sequence initiated and displayed.")}),n.addEventListener("click",()=>{e.classList.add("hidden"),console.log("Modal sequence terminated and hidden.")})});